function longestUnique(s) {
  // Two pointers: left and right.
  // Walk right through the string.
  //   If s[right] is already in the window, move left past the previous occurrence.
  // Track max window length.
  // A Map<char, lastIndex> lets you jump left in O(1).
}

solution:
// O(n) time, O(min(n, alphabet)) space.
function longestUnique(s) {
  const lastSeen = new Map();
  let left = 0;
  let best = 0;
  for (let right = 0; right < s.length; right++) {
    const ch = s[right];
    // If we've seen this char inside the current window, move left past it
    if (lastSeen.has(ch) && lastSeen.get(ch) >= left) {
      left = lastSeen.get(ch) + 1;
    }
    lastSeen.set(ch, right);
    best = Math.max(best, right - left + 1);
  }
  return best;
}
